function candidate(value) {
  if (typeof value !== "string" || value.length === 0) {
    return false;
  }

  var types = {
    html: "text/html",
    htm: "text/html",
    shtml: "text/html",
    js: "application/javascript",
    mjs: "application/javascript",
    json: "application/json",
    map: "application/json",
    rtf: "application/rtf",
    txt: "text/plain",
    text: "text/plain",
    conf: "text/plain",
    def: "text/plain",
    list: "text/plain",
    log: "text/plain",
    in: "text/plain",
    ini: "text/plain",
    xml: "application/xml",
    xsl: "application/xml",
    xsd: "application/xml",
    css: "text/css",
    csv: "text/csv",
    md: "text/markdown",
    markdown: "text/markdown",
    pdf: "application/pdf",
    zip: "application/zip",
    gz: "application/gzip",
    gif: "image/gif",
    jpg: "image/jpeg",
    jpeg: "image/jpeg",
    png: "image/png",
    svg: "image/svg+xml",
    webp: "image/webp",
    ico: "image/vnd.microsoft.icon",
    mp3: "audio/mpeg",
    mp4: "video/mp4",
    mpeg: "video/mpeg",
    webm: "video/webm",
    wasm: "application/wasm"
  };

  var normalized = value.toLowerCase();
  var slash = Math.max(normalized.lastIndexOf("/"), normalized.lastIndexOf("\\"));
  var name = normalized.slice(slash + 1);
  var dot = name.lastIndexOf(".");
  var suffix = dot === -1 ? name : name.slice(dot + 1);

  if (!suffix || (dot === 0 && slash !== -1 && name.indexOf(".", 1) === -1)) {
    return false;
  }

  return types[suffix] || false;
}
